void RegisterWrapBox()
{
	using namespace sketch;
	FFactory Factory;
	Factory.Name = TEXT("WrapBox");
	Factory.ConstructWidget = [](SWidget* WidgetToTakeUniqueSlotsFrom)
		{
			SWrapBox::FArguments Arguments;
			Arguments
				.PreferredSize(Sketch("PreferredSize", float(100.f)))
				.HAlign(Sketch("HAlign", EHorizontalAlignment(HAlign_Left)))
				.InnerSlotPadding(Sketch("InnerSlotPadding", FVector2D(FVector2D::ZeroVector)))
				.UseAllottedSize(Sketch("UseAllottedSize", bool(false)))
				.Orientation(Sketch("Orientation", EOrientation(EOrientation::Orient_Horizontal)))
				.SKETCH_WIDGET_FACTORY_BOILERPLATE();
			TSharedRef<SWrapBox> Widget = SArgumentNew(Arguments, SWrapBox);
			return MoveTemp(Widget);
		};
	Factory.EnumerateDynamicSlotTypes = [](const SWidget& Widget) -> FFactory::FDynamicSlotTypes
		{
			FFactory::FDynamicSlotTypes Result;
			Result.Reserve(1);
			Result = { TEXT("FSlot"), };
			return Result;
		};
	Factory.ConstructDynamicSlot = [](SWidget& Widget, const FName& SlotType) -> ::FSlotBase&
		{
			check(SlotType == TEXT("FSlot"));
			SWrapBox::FSlot* Slot;
			{
				decltype(auto) SlotArgs = static_cast<SWrapBox&>(Widget).AddSlot();
				SlotArgs
					.FillLineWhenSizeLessThan(Sketch("FillLineWhenSizeLessThan", TOptional<float>()))
					.FillEmptySpace(Sketch("FillEmptySpace", TOptional<bool>()))
					.ForceNewLine(Sketch("ForceNewLine", TOptional<bool>()))
					;
				Slot = SlotArgs.GetSlot();
			}
			return *Slot;
		};
	Factory.DestroyDynamicSlot = &HeaderTool::DestroyDynamicSlot<SWrapBox>;
	FSketchCore& Core = FSketchCore::Get();
	Core.RegisterFactory(TEXT("Layout"), MoveTemp(Factory));
}

